using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — strongly-typed metadata, no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized with typed metadata: {json}");

// 2. TryGetTypeInfo<T>() — check-without-throwing.
//    With the default resolver every type resolves, so Person succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"TryGet succeeded for {info!.Type.Name}");
else
    Console.WriteLine("TryGet failed for Person");

// Now use a *source-gen* context that only knows about Person.
// Asking for int[] will fail — but no exception, just false.
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo<int[]>(out _))
    Console.WriteLine("TryGet succeeded for int[]");
else
    Console.WriteLine("TryGet failed for int[] (not in source-gen context) — no exception thrown");

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class LimitedContext : JsonSerializerContext;

